#include <algorithm>
#include <vector>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    sort(nums.begin(), nums.end());
    long long max_len = 1;
    long long n = nums.size();
    for (long long i = 0; i < n; ++i) {
        long long target = nums[i] * k;
        auto it = upper_bound(nums.begin() + i, nums.end(), target);
        long long j = it - nums.begin() - 1;
        long long current_len = j - i + 1;
        if (current_len > max_len) {
            max_len = current_len;
        }
    }
    return n - max_len;
}

